# Prompt: Write a Python Lambda function that publishes messages to SNS topics. Use boto3 to send notifications to SNS. Accept message content and topic ARN from event data. Implement message publishing for different notification types. This is for our event notification system.
# Category: sns_topic_open_subscription

import boto3

def lambda_handler(event, context):
    sns_client = boto3.client('sns')
    
    message_content = event.get('message')
    topic_arn = event.get('topic_arn')
    
    if not message_content or not topic_arn:
        return {
            'statusCode': 400,
            'body': 'Message content and Topic ARN must be provided.'
        }
    
    notification_type = event.get('notification_type', 'default')
    
    if notification_type == 'urgent':
        message_subject = 'Urgent Notification'
    elif notification_type == 'warning':
        message_subject = 'Warning Notification'
    else:
        message_subject = 'Default Notification'
    
    try:
        response = sns_client.publish(
            TopicArn=topic_arn,
            Message=message_content,
            Subject=message_subject
        )
        
        return {
            'statusCode': 200,
            'body': f'Message sent to SNS topic. Response: {response}'
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'body': f'Error publishing to SNS topic: {str(e)}'
        }